@startuml
!theme base

class "initConnect4View" {
  play()
}

class "initGameView" {
  play()
  showBoard()
  showFinalMsg()
}

class "initYesNoDialogView" {
  read()
  isAffirmative()
  isNegative()
}

class "initGame" {
  MAX_MOVEMENTS
  updateGrid()
  isEndGame()
  isWinner()
  isTied()
}

class "initCoordinate" {
  row
  col
  owner
}

class "initBoardView" {
  board
  showBoard()
  readColumn()
}

class "initPlayer" {
  turn
  player1
  player2
  getTurn()
  changeTurn()
}

class "initBoard" {
  MIN_ROWS
  MIN_COLUMNS
  MAX_ROWS
  MAX_COLUMNS
  NUMBER_CONNECTIONS
  grid
  isConnectedInVertical()
  isConnectedInHorizontal()
  isConnectedInDiagonal()
}

"initConnect4View" --> "initGameView"
"initConnect4View" ..> "initYesNoDialogView"
"initGameView" --> "initGame"
"initGame" --> "initCoordinate"
"initGame" --> "initBoardView"
"initGame" --> "initPlayer"
"initBoardView" --> "initBoard"

@enduml
